// Adaptive Sorting Algorithm Implementation
// This program implements a sorting algorithm that can be evolved to adapt to different data patterns

use std::cmp::Ordering;

// EVOLVE-BLOCK-START
pub fn adaptive_sort<T: Ord + Clone>(arr: &mut [T]) {
    let n = arr.len();
    if n < 2 { return }
    let (mut s, mut r) = (true, true);
    for i in 1..n {
        if arr[i-1] > arr[i] { s = false }
        else if arr[i-1] < arr[i] { r = false }
        if !s && !r { break }
    }
    if s { return }
    if r { arr.reverse(); return }
    if n < 24 { insertion_sort(arr); return }
    quicksort(arr, 0, n - 1)
}

fn quicksort<T: Ord + Clone>(arr: &mut [T], mut l: usize, mut h: usize) {
    while l < h {
        if h - l < 24 { insertion_sort(&mut arr[l..=h]); return }
        let (lt, gt) = partition_3way(arr, l, h);
        if lt - l < h - gt {
            if lt > l { quicksort(arr, l, lt - 1) }
            l = gt + 1
        } else {
            quicksort(arr, gt + 1, h);
            if lt > l { h = lt - 1 } else { break }
        }
    }
}

fn partition_3way<T: Ord + Clone>(arr: &mut [T], l: usize, h: usize) -> (usize, usize) {
    let m = l + (h - l) / 2;
    if arr[m] < arr[l] { arr.swap(m, l) }
    if arr[h] < arr[l] { arr.swap(h, l) }
    if arr[h] < arr[m] { arr.swap(h, m) }
    let p = arr[m].clone();
    let (mut lt, mut i, mut gt) = (l, l, h);
    while i <= gt {
        match arr[i].cmp(&p) {
            Ordering::Less => { if lt < i { arr.swap(lt, i) } lt += 1; i += 1 }
            Ordering::Greater => { if i < gt { arr.swap(i, gt) } if gt == 0 { break } gt -= 1 }
            _ => i += 1,
        }
    }
    (lt, gt)
}

fn insertion_sort<T: Ord + Clone>(arr: &mut [T]) {
    for i in 1..arr.len() {
        if arr[i] < arr[i-1] {
            let v = arr[i].clone();
            let mut j = i;
            while j > 0 && arr[j-1] > v {
                arr[j] = arr[j-1].clone();
                j -= 1;
            }
            arr[j] = v;
        }
    }
}
// EVOLVE-BLOCK-END

// Benchmark function to test the sort implementation
pub fn run_benchmark(test_data: Vec<Vec<i32>>) -> BenchmarkResults {
    let mut results = BenchmarkResults {
        times: Vec::new(),
        correctness: Vec::new(),
        adaptability_score: 0.0,
    };

    for data in test_data {
        let mut arr = data.clone();
        let start = std::time::Instant::now();

        adaptive_sort(&mut arr);

        let elapsed = start.elapsed();
        results.times.push(elapsed.as_secs_f64());

        // Check if correctly sorted
        let is_sorted = arr.windows(2).all(|w| w[0] <= w[1]);
        results.correctness.push(is_sorted);
    }

    // Calculate adaptability score based on performance variance
    if results.times.len() > 1 {
        let mean_time: f64 = results.times.iter().sum::<f64>() / results.times.len() as f64;
        let variance: f64 = results.times.iter()
            .map(|t| (t - mean_time).powi(2))
            .sum::<f64>() / results.times.len() as f64;

        // Lower variance means better adaptability
        results.adaptability_score = 1.0 / (1.0 + variance.sqrt());
    }

    results
}

#[derive(Debug)]
pub struct BenchmarkResults {
    pub times: Vec<f64>,
    pub correctness: Vec<bool>,
    pub adaptability_score: f64,
}

