pub fn adaptive_sort<T: Ord + Clone>(arr: &mut [T]) {
    let n = arr.len();
    if n < 24 { insertion_sort(arr); return }
    let (mut s, mut r) = (true, true);
    for i in 1..n {
        match arr[i-1].cmp(&arr[i]) {
            Ordering::Greater => s = false,
            Ordering::Less => r = false,
            _ => {}
        }
        if !s && !r { break }
    }
    if s { return }
    if r { arr.reverse(); return }
    quicksort(arr, 0, n - 1)
}
